// ─── Dashboard Service ─────────────────────────────────────────
// Fetches all data from Spring Boot backend and normalizes for frontend.

import { apiFetch } from '../../../shared/utils/api';

export const fetchDashboardData = async () => {
  const [transactions, categoryBreakdown] = await Promise.all([
    apiFetch('/transactions'),
    apiFetch('/transactions/summary/category'),
  ]);

  const normalized    = normalizeTransactions(transactions);
  const monthlyTrends = buildMonthlyTrends(normalized); // ✅ Bug#1 fix: use normalized (credit/debit) not raw
  const budgets       = buildBudgets(categoryBreakdown);

  return { transactions: normalized, monthlyTrends, budgets };
};

// ─── Helpers ──────────────────────────────────────────────────

// Normalize backend format → frontend format
const normalizeTransactions = (transactions) =>
  transactions.map((t) => ({
    id:          t.id,
    date:        t.date,
    description: t.title,
    // ✅ Bug#3 fix: store original backend category lowercased for consistent matching
    amount:      t.type === 'EXPENSE' ? -Math.abs(t.amount) : t.amount,
    category:    mapCategory(t.category),
    type:        t.type === 'INCOME' ? 'credit' : 'debit',
  }));

// Map backend category strings → frontend category ids (case-insensitive)
export const mapCategory = (cat = '') => {
  const map = {
    'food': 'food', 'salary': 'income', 'income': 'income',
    'rent': 'utilities', 'transport': 'transport', 'shopping': 'shopping',
    'entertainment': 'entertainment', 'health': 'health', 'utilities': 'utilities',
  };
  return map[cat.toLowerCase()] || cat.toLowerCase();
};

// Build last 6 months trend data — uses normalized credit/debit types
const buildMonthlyTrends = (normalizedTransactions) => {
  const months = [];
  for (let i = 5; i >= 0; i--) {
    const d = new Date();
    d.setDate(1); // avoid month-end overflow
    d.setMonth(d.getMonth() - i);
    months.push({
      month:    d.toLocaleString('en-IN', { month: 'short' }),
      year:     d.getFullYear(),
      monthNum: d.getMonth(),
    });
  }

  return months.map(({ month, year, monthNum }) => {
    const txns = normalizedTransactions.filter((t) => {
      if (!t.date) return false;
      // ✅ Bug#12 fix: parse date as local not UTC by replacing '-' with '/'
      const d = new Date(String(t.date).replace(/-/g, '/'));
      return d.getMonth() === monthNum && d.getFullYear() === year;
    });
    // ✅ Bug#1 fix: correctly uses normalized 'credit'/'debit' types
    const income   = txns.filter((t) => t.type === 'credit').reduce((s, t) => s + t.amount, 0);
    const expenses = txns.filter((t) => t.type === 'debit').reduce((s, t) => s + Math.abs(t.amount), 0);
    return { month, income, expenses };
  });
};

// Build budget limits per category from backend spending data
const buildBudgets = (categoryBreakdown) => {
  const defaults = {
    food: 5000, transport: 3000, shopping: 8000,
    entertainment: 3000, health: 4000, utilities: 3000,
  };
  // Adjust defaults upward if actual spending is higher
  Object.entries(categoryBreakdown).forEach(([cat, spent]) => {
    const key = mapCategory(cat);
    if (key !== 'income' && spent > 0) {
      defaults[key] = Math.max(defaults[key] || 0, Math.round(spent * 1.3));
    }
  });
  return Object.entries(defaults).map(([category, limit]) => ({ category, limit }));
};
